import type {
  RespondentState,
  ContinuousNodeId,
  CategoricalNodeId,
  NodeId,
} from "../types.js";
import { isSelfNode } from "../config/nodes.js";

/**
 * Respondent's per-node expected position and salience, derived from the
 * posterior state at quiz end. Shape mirrors the {pos, sal} fields on an
 * archetype so downstream distance code can consume either.
 *
 * Scale matches candidate/archetype encoding:
 *   - continuous nodes: pos on the 1-5 scale
 *   - categorical nodes (EPS/AES): pos as 0-5 expected index
 *   - salience on the 0-3 scale
 */
export interface NodeSignatureEntry {
  pos: number;
  sal: number;
  /** Full categorical distribution for EPS/AES (added 2026-04-25 for vote
   *  alignment via per-category match rather than expected-index proxy).
   *  Undefined for continuous nodes. */
  catDist?: number[];
}

export type NodeSignature = Partial<Record<NodeId, NodeSignatureEntry>>;

function expectedContinuousPos(dist: ArrayLike<number>): number {
  let e = 0;
  for (let i = 0; i < 5; i++) e += (dist[i] ?? 0) * (i + 1);
  return e;
}

function expectedCategoricalIndex(dist: ArrayLike<number>): number {
  let e = 0;
  for (let i = 0; i < 6; i++) e += (dist[i] ?? 0) * i;
  return e;
}

function expectedSalience(dist: ArrayLike<number>): number {
  let e = 0;
  for (let i = 0; i < 4; i++) e += (dist[i] ?? 0) * i;
  return e;
}

export function respondentSignatureFromState(state: RespondentState): NodeSignature {
  const sig: NodeSignature = {};
  for (const [nodeId, node] of Object.entries(state.continuous)) {
    const pos = expectedContinuousPos(node.posDist);
    // SELF-cluster (PF/TRB/ENG) is activation-only per ADR-005. salDist is
    // initialized but never updated for these nodes, so reading it returns the
    // uniform E[sal]=1.5 fallback regardless of actual activation. Derive sal
    // from pos instead: pos 1 → sal 0, pos 5 → sal 3 (linear on the 0-3 scale).
    const sal = isSelfNode(nodeId)
      ? ((pos - 1) / 4) * 3
      : expectedSalience(node.salDist);
    sig[nodeId as ContinuousNodeId] = { pos, sal };
  }
  for (const [nodeId, node] of Object.entries(state.categorical)) {
    sig[nodeId as CategoricalNodeId] = {
      pos: expectedCategoricalIndex(node.catDist),
      sal: expectedSalience(node.salDist),
      catDist: [...node.catDist],
    };
  }
  return sig;
}
