import type {
  CategoricalDist,
  ContinuousNodeId,
  CategoricalNodeId,
  OptionEvidence,
  PairOptionMap,
  QuestionDef,
  RespondentState,
  SalienceDist
} from "../types.js";
import { multiplyAndNormalize, multiplyAndNormalizeTempered, normalize, addToAnchorDist } from "./math.js";
import { isSelfNode } from "../config/nodes.js";

// Tempering exponent for categorical (EPS/AES) `cat` updates.
// τ < 1 flattens likelihoods before Bayesian multiply, preventing runaway
// concentration on a single dominant category. Sweep rationale in
// results/categorical-tempering/. Default chosen conservative (0.7): enough
// to soften compounding without dissolving discriminative signal.
const CAT_TEMPERING_TAU = 0.7;
import { NODE_NORM_FACTORS } from "../config/normalization.js";

// Salience likelihood ratios keyed by rank position (6-item ranking).
// Rank 1 = most important → high salience; Rank 6 = least → low salience.
const RANK_SAL: SalienceDist[] = [
  [0.05, 0.15, 0.30, 0.50],  // rank 1 (most important)
  [0.10, 0.20, 0.30, 0.40],  // rank 2
  [0.18, 0.25, 0.30, 0.27],  // rank 3
  [0.27, 0.30, 0.25, 0.18],  // rank 4
  [0.40, 0.30, 0.20, 0.10],  // rank 5
  [0.50, 0.30, 0.15, 0.05],  // rank 6 (least important)
];

// Salience likelihoods for the pure-salience best-worst battery (top-N / bottom-N).
// Applied per item based on whether it was picked as best, worst, or left in the middle.
const SAL_IF_BEST:   SalienceDist = [0.05, 0.15, 0.30, 0.50];
const SAL_IF_WORST:  SalienceDist = [0.50, 0.30, 0.15, 0.05];
const SAL_IF_MIDDLE: SalienceDist = [0.25, 0.30, 0.25, 0.20];

// Near-flat salience likelihoods for "category-pick" best_worst questions,
// where every item touches the same node (e.g. Q89 EPS). The user is forced to
// pick among 6 phrasings of one categorical node; that pick reveals their
// category strongly but carries essentially no salience information (they had
// to pick something no matter how much they care). Any salience signal on that
// node must come from other questions whose likelihood actually depends on the
// respondent's answer content (e.g. Q22 allocation HHI, Q79 option choice).
// For node-salience batteries (Q86/Q88) each item maps to a distinct node, so
// a "best" pick is genuine relative-importance signal — keep the strong form.
const SAL_IF_BEST_FORCED:  SalienceDist = [0.23, 0.25, 0.27, 0.25];
const SAL_IF_WORST_FORCED: SalienceDist = [0.27, 0.25, 0.25, 0.23];

// Category-mix weights when a best_worst item carries categorical evidence
// (e.g. EPS / AES style picks). Best is a stronger signal than worst —
// people more reliably name what they prefer than what they reject.
const BW_BEST_CAT_MIX = 0.50;
const BW_WORST_CAT_MIX = 0.30;

// Continuous-position mix weights for pole-battery best_worst items (Q93-Q96).
// Lighter than category because priority picks only weakly pin exact position —
// picking "economic fairness" as top priority doesn't mean position=1 exactly,
// just a redistributionist lean. Worst pick pulls away from the pole similarly
// but more gently (people are more certain of what they want than what they don't).
const BW_BEST_POS_MIX = 0.35;
const BW_WORST_POS_MIX = 0.22;

// Priority-sort (card-sort) salience likelihoods. Each item gets dropped into
// one of three buckets: "high" = super-important, "mid" = care but not central,
// "low" = not central. This is a richer signal than best-worst because many
// items can land in each bucket — we don't force a forced-choice artifact.
// Likelihoods are shaped strongly because a deliberate placement is genuine
// importance signal (cf. SAL_IF_BEST [0.05,0.15,0.30,0.50]).
const SAL_PRIORITY_HIGH: SalienceDist = [0.03, 0.10, 0.27, 0.60];
const SAL_PRIORITY_MID:  SalienceDist = [0.20, 0.30, 0.30, 0.20];
const SAL_PRIORITY_LOW:  SalienceDist = [0.55, 0.30, 0.12, 0.03];

// Priority-sort position mix weights. High-bucket placement pulls the position
// posterior toward the pole harder than best-worst best (BW_BEST_POS_MIX=0.35)
// because the user could have placed the item in a weaker bucket — choosing
// "high" is a stronger signal. Mid bucket pulls gently; low bucket skips
// position entirely (placing something in "not central" tells us nothing about
// which pole the user falls on — only that the node is low-salience).
const PRIORITY_HIGH_POS_MIX = 0.40;
const PRIORITY_MID_POS_MIX  = 0.20;

// Dual-axis convex mix weight for the position update. Slightly stronger than
// priority-sort high-bucket (0.40) because the user made a precise placement
// on a continuous axis rather than a coarse bucket pick.
const DUAL_AXIS_POS_MIX = 0.45;

// Dual-axis salience likelihoods keyed on y ∈ [0,1] (0 = "doesn't matter",
// 1 = "central"). Shaped similarly to SAL_PRIORITY_* but on a 5-band split.
function dualAxisYtoSal(y: number): SalienceDist {
  if (y >= 0.80) return [0.03, 0.10, 0.27, 0.60];
  if (y >= 0.60) return [0.10, 0.20, 0.32, 0.38];
  if (y >= 0.40) return [0.22, 0.30, 0.28, 0.20];
  if (y >= 0.20) return [0.40, 0.30, 0.20, 0.10];
  return [0.60, 0.25, 0.12, 0.03];
}

function invertCatDist(d: CategoricalDist): CategoricalDist {
  const inv = d.map((p) => 1 - p);
  const total = inv.reduce((a, b) => a + b, 0);
  if (total <= 0) return d;
  return inv.map((p) => p / total) as CategoricalDist;
}

// Extremity → salience. When a respondent lands at an extreme on a position
// scale, it's a signal the node is cognitively active for them (you don't
// hold extreme opinions on things you don't care about). This likelihood is
// milder than SAL_IF_BEST because the position itself — not an explicit
// "rank this as most important" — is doing the signaling.
const EXTREMITY_SAL: SalienceDist = [0.10, 0.20, 0.30, 0.40];

// Default engagement salience (added 2026-04-24 per diagnose-question-signals
// audit). Applied to any non-SELF node when the chosen option emits position
// evidence but no explicit salience likelihoods. Rationale: 50 questions in
// the bank declare position touches without calibrated sal fields — answering
// the question at all is implicit evidence that the node is somewhat active.
// Very gentle distribution (nearly uniform with slight middle peak) so this
// default does not erode explicit high-sal signals (e.g., Q103 lockings) when
// the same node is subsequently probed via pos-only questions. Over many
// applications this converges to a sharper E[sal]=1.5 distribution rather
// than pushing sal up or down.
const DEFAULT_ENGAGEMENT_SAL: SalienceDist = [0.22, 0.28, 0.28, 0.22];

function isExtremePosEvidence(pos: readonly number[] | undefined): boolean {
  if (!pos || pos.length !== 5) return false;
  const max = Math.max(...pos);
  if (max < 0.40) return false;
  const maxIdx = pos.indexOf(max);
  return maxIdx === 0 || maxIdx === 4;
}

function boostExtremitySalience(
  state: RespondentState,
  q: QuestionDef,
  nodesToBoost: Set<string>
): void {
  if (nodesToBoost.size === 0) return;
  for (const touch of q.touchProfile) {
    if (touch.role !== "position") continue;
    if (!nodesToBoost.has(touch.node as string)) continue;
    if (touch.kind === "continuous" && touch.node in state.continuous) {
      if (isSelfNode(touch.node)) continue; // SELF-cluster: activation-only, no sal dim
      const node = state.continuous[touch.node as ContinuousNodeId];
      node.salDist = multiplyAndNormalize(node.salDist, EXTREMITY_SAL);
    } else if (touch.kind === "categorical" && touch.node in state.categorical) {
      const node = state.categorical[touch.node as CategoricalNodeId];
      node.salDist = multiplyAndNormalize(node.salDist, EXTREMITY_SAL);
    }
  }
}

function registerTouches(state: RespondentState, q: QuestionDef): void {
  for (const touch of q.touchProfile) {
    if (touch.node === "TRB_ANCHOR") continue;
    if (touch.kind === "continuous" && touch.node in state.continuous) {
      const node = state.continuous[touch.node as ContinuousNodeId];
      node.touches += 1;
      node.touchTypes.add(touch.touchType);
    } else if (touch.kind === "categorical" && touch.node in state.categorical) {
      const node = state.categorical[touch.node as CategoricalNodeId];
      node.touches += 1;
      node.touchTypes.add(touch.touchType);
    }
  }
}

// TODO: applyOptionEvidence uses pre-computed likelihood ratios, so NODE_NORM_FACTORS
// should be applied when the evidence is constructed (in question authoring), not here
// at runtime. Future work: bake norm factors into the optionEvidence generation pipeline.
function applyOptionEvidence(state: RespondentState, evidence: OptionEvidence | undefined): void {
  if (!evidence) return;

  if (evidence.continuous) {
    for (const [nodeId, upd] of Object.entries(evidence.continuous)) {
      const node = state.continuous[nodeId as ContinuousNodeId];
      if (upd?.pos) node.posDist = multiplyAndNormalize(node.posDist, upd.pos);
      // SELF-cluster (PF/TRB/ENG) skips sal writes: pos is the activation axis.
      if (upd?.sal && !isSelfNode(nodeId)) {
        node.salDist = multiplyAndNormalize(node.salDist, upd.sal);
      } else if (upd?.pos && !isSelfNode(nodeId)) {
        node.salDist = multiplyAndNormalize(node.salDist, DEFAULT_ENGAGEMENT_SAL);
      }
    }
  }

  if (evidence.categorical) {
    for (const [nodeId, upd] of Object.entries(evidence.categorical)) {
      const node = state.categorical[nodeId as CategoricalNodeId];
      if (upd?.cat) node.catDist = multiplyAndNormalizeTempered(node.catDist, upd.cat, CAT_TEMPERING_TAU);
      if (upd?.sal) {
        node.salDist = multiplyAndNormalize(node.salDist, upd.sal);
      } else if (upd?.cat) {
        node.salDist = multiplyAndNormalize(node.salDist, DEFAULT_ENGAGEMENT_SAL);
      }
    }
  }

  if (evidence.trbAnchor) {
    state.trbAnchor.dist = addToAnchorDist(state.trbAnchor.dist, evidence.trbAnchor);
    state.trbAnchor.touches += 1;
  }
}

function applyContinuousSignal(
  state: RespondentState,
  nodeId: ContinuousNodeId,
  signal: number,
  strength = 1.0
): void {
  const node = state.continuous[nodeId];
  if (!node || signal === 0 || strength === 0) return;
  const normFactor = NODE_NORM_FACTORS[nodeId] ?? 1;
  const bump = node.posDist.map((p, i) =>
    p * Math.exp(signal * normFactor * strength * ((i + 1) - 3))
  );
  node.posDist = normalize(bump as typeof node.posDist);
}

function mixCategoricalTarget(
  state: RespondentState,
  nodeId: CategoricalNodeId,
  target: CategoricalDist,
  weight: number
): void {
  const node = state.categorical[nodeId];
  if (!node) return;
  const w = Math.max(0, Math.min(1, weight));
  if (w === 0) return;
  const mixed = node.catDist.map((v, i) => v * (1 - w) + (target[i] ?? 0) * w);
  node.catDist = normalize(mixed as typeof node.catDist);
}

function mixContinuousTarget(
  state: RespondentState,
  nodeId: ContinuousNodeId,
  target: readonly number[],
  weight: number
): void {
  const node = state.continuous[nodeId];
  if (!node) return;
  const w = Math.max(0, Math.min(1, weight));
  if (w === 0) return;
  const sum = target.reduce((a, b) => a + b, 0) || 1;
  const normTarget = target.map(v => v / sum) as typeof node.posDist;
  const mixed = node.posDist.map((v, i) => v * (1 - w) + (normTarget[i] ?? 0) * w);
  node.posDist = normalize(mixed as typeof node.posDist);
}

function shareMap(allocation: Record<string, number>, total: number): Record<string, number> {
  const out: Record<string, number> = {};
  for (const [k, v] of Object.entries(allocation)) out[k] = v / total;
  return out;
}

const EPS_HUMBLE_INSTITUTIONAL: CategoricalDist = [0.42, 0.38, 0.05, 0.05, 0.08, 0.02];
const EPS_CERTAINTY_SELF: CategoricalDist = [0.08, 0.05, 0.06, 0.34, 0.37, 0.10];

function applyAllocationShapeSignals(
  state: RespondentState,
  q: QuestionDef,
  shares: Record<string, number>
): void {
  const values = Object.values(shares);
  if (values.length < 2) return;

  const maxShare = Math.max(...values);
  const minShare = Math.min(...values);
  const zeroCount = values.filter(v => v <= 0.001).length;
  const hhi = values.reduce((sum, v) => sum + v * v, 0);

  // Generic shape signal: monocausal allocations are a modest low-COM /
  // high-certainty cue regardless of which bucket won.
  if (maxShare >= 0.85 || hhi >= 0.75) {
    applyContinuousSignal(state, "COM", -0.30, maxShare >= 0.95 ? 1.2 : 1.0);
    mixCategoricalTarget(state, "EPS", EPS_CERTAINTY_SELF, maxShare >= 0.95 ? 0.14 : 0.10);
  } else if (maxShare >= 0.70) {
    applyContinuousSignal(state, "COM", -0.16);
    mixCategoricalTarget(state, "EPS", EPS_CERTAINTY_SELF, 0.06);
  }

  // A genuinely even allocation is a weak humility / plural-cause signal.
  if (minShare >= 0.20 && maxShare <= 0.30) {
    applyContinuousSignal(state, "COM", 0.22);
    mixCategoricalTarget(state, "EPS", EPS_HUMBLE_INSTITUTIONAL, 0.08);
  }

  if (zeroCount > 0) {
    applyContinuousSignal(state, "COM", -0.08 * Math.min(zeroCount, 2));
  }

  applyAllocationDomainSignals(state, q, shares);
}

function applyAllocationDomainSignals(
  state: RespondentState,
  q: QuestionDef,
  s: Record<string, number>
): void {
  if (q.id === 15) {
    const structural = (s.family_background ?? 0) + (s.discrimination_bias ?? 0);
    const effort = s.effort_choices ?? 0;
    const luck = s.luck_random ?? 0;
    const bias = s.discrimination_bias ?? 0;
    if (effort >= 0.70) {
      applyContinuousSignal(state, "MAT", 0.30);
      applyContinuousSignal(state, "COM", -0.10);
    }
    if (structural >= 0.80 && effort <= 0.10) {
      applyContinuousSignal(state, "MAT", -0.28);
      applyContinuousSignal(state, "ZS", 0.18);
    }
    if (effort + luck >= 0.85 && bias <= 0.05) {
      applyContinuousSignal(state, "MAT", 0.25);
      applyContinuousSignal(state, "ZS", -0.12);
    }
    return;
  }

  if (q.id === 20) {
    const complex = s.complex_forces ?? 0;
    const selfish = s.powerful_selfish ?? 0;
    const incompetent = s.powerful_incompetent ?? 0;
    const ordinary = s.ordinary_choices ?? 0;
    if (complex >= 0.60) {
      applyContinuousSignal(state, "ZS", -0.32);
      applyContinuousSignal(state, "COM", 0.18);
      mixCategoricalTarget(state, "EPS", EPS_HUMBLE_INSTITUTIONAL, 0.10);
    }
    if (selfish >= 0.60 && ordinary <= 0.05) {
      applyContinuousSignal(state, "ZS", 0.45);
      applyContinuousSignal(state, "ONT_H", -0.32);
      applyContinuousSignal(state, "COM", -0.32);
    }
    if (incompetent >= selfish * 2 && incompetent >= 0.30) {
      applyContinuousSignal(state, "ZS", -0.14);
      applyContinuousSignal(state, "ONT_H", -0.12);
    }
    return;
  }

  if (q.id === 39) {
    const legit = s.legitimate_values ?? 0;
    const misinformed = s.misinformed ?? 0;
    const bad = s.bad_motives ?? 0;
    if (legit >= 0.50) {
      applyContinuousSignal(state, "COM", 0.45);
      applyContinuousSignal(state, "TRB", -0.35);
      applyContinuousSignal(state, "ZS", -0.35);
      applyContinuousSignal(state, "MOR", 0.25);
    }
    if (legit <= 0.02 && bad >= 0.50) {
      applyContinuousSignal(state, "COM", -0.55);
      applyContinuousSignal(state, "TRB", 0.55);
      applyContinuousSignal(state, "ZS", 0.50);
      applyContinuousSignal(state, "MOR", -0.35);
    }
    if (misinformed >= 0.60 && bad <= 0.10) {
      mixCategoricalTarget(state, "EPS", [0.45, 0.30, 0.04, 0.06, 0.12, 0.03], 0.12);
      applyContinuousSignal(state, "COM", 0.08);
    }
    return;
  }

  if (q.id === 66) {
    const heritage = s.preserve_heritage ?? 0;
    const modernize = s.modernize_infrastructure ?? 0;
    const deliberation = s.community_deliberation ?? 0;
    const market = s.market_based_development ?? 0;
    if (modernize + market >= 0.80) {
      applyContinuousSignal(state, "MAT", 0.22);
      applyContinuousSignal(state, "COM", -0.14);
      mixCategoricalTarget(state, "EPS", EPS_HUMBLE_INSTITUTIONAL, 0.06);
    }
    if (heritage + deliberation >= 0.75) {
      applyContinuousSignal(state, "COM", 0.25);
      mixCategoricalTarget(state, "EPS", [0.08, 0.18, 0.34, 0.20, 0.12, 0.08], 0.08);
    }
    if (deliberation >= 0.60) {
      applyContinuousSignal(state, "PRO", 0.35);
      applyContinuousSignal(state, "COM", 0.35);
    }
  }
}

function applyPriorityPatternSignals(
  state: RespondentState,
  q: QuestionDef,
  placements: {
    supportHigh: string[];
    supportMid: string[];
    neutral: string[];
    opposeHigh: string[];
  }
): void {
  const high = new Set(placements.supportHigh);
  const mid = new Set(placements.supportMid);
  const low = new Set(placements.neutral);
  const isHigh = (item: string) => high.has(item);
  const isNotHigh = (item: string) => !high.has(item);
  const isLow = (item: string) => low.has(item);

  if (q.id === 60) {
    const inheritedRight =
      isHigh("national_identity") &&
      (isHigh("religious_identity") || isHigh("ethnic_racial_identity")) &&
      isLow("global_citizen") &&
      isLow("gender_identity") &&
      isLow("sexual_identity");
    if (inheritedRight) {
      applyContinuousSignal(state, "TRB", 0.35);
      applyContinuousSignal(state, "CU", -0.25);
      applyContinuousSignal(state, "MOR", -0.20);
      applyContinuousSignal(state, "CD", 0.25);
    }

    const intersectional =
      (isHigh("gender_identity") || isHigh("sexual_identity")) &&
      isHigh("ethnic_racial_identity") &&
      (isHigh("class_identity") || isHigh("ideological_identity")) &&
      isLow("religious_identity") &&
      isLow("national_identity");
    if (intersectional) {
      applyContinuousSignal(state, "CD", -0.28);
      applyContinuousSignal(state, "CU", 0.24);
      applyContinuousSignal(state, "MOR", 0.18);
      applyContinuousSignal(state, "MAT", -0.16);
      applyContinuousSignal(state, "TRB", 0.18);
    }

    const postIdentity =
      (high.size === 0 && mid.size <= 1) ||
      (isHigh("ideological_identity") && high.size <= 2 &&
        isNotHigh("national_identity") &&
        isNotHigh("religious_identity") &&
        isNotHigh("ethnic_racial_identity") &&
        isNotHigh("gender_identity") &&
        isNotHigh("sexual_identity"));
    if (postIdentity) {
      applyContinuousSignal(state, "TRB", -0.45);
      applyContinuousSignal(state, "CU", 0.10);
      applyContinuousSignal(state, "MOR", 0.08);
    }
    return;
  }

  if (q.id === 102) {
    const essential = high;
    const irrelevant = low;
    const civicNationalist =
      essential.has("shared_values") &&
      essential.has("civic_part") &&
      irrelevant.has("ancestry") &&
      irrelevant.has("religion") &&
      !essential.has("ancestry") &&
      !essential.has("religion");
    if (civicNationalist) {
      mixContinuousTarget(state, "CU", [0.05, 0.12, 0.30, 0.35, 0.18], 0.22);
      mixContinuousTarget(state, "MOR", [0.03, 0.08, 0.20, 0.36, 0.33], 0.24);
      mixContinuousTarget(state, "PRO", [0.03, 0.08, 0.20, 0.34, 0.35], 0.20);
      mixContinuousTarget(state, "TRB", [0.38, 0.32, 0.20, 0.07, 0.03], 0.18);
      applyContinuousSignal(state, "CD", -0.10);
    }

    const ethnoTraditionalist =
      (essential.has("born_here") || essential.has("ancestry")) &&
      (essential.has("religion") || essential.has("cultural")) &&
      !essential.has("shared_values");
    if (ethnoTraditionalist) {
      mixContinuousTarget(state, "CU", [0.55, 0.28, 0.12, 0.04, 0.01], 0.28);
      mixContinuousTarget(state, "CD", [0.02, 0.05, 0.13, 0.30, 0.50], 0.26);
      mixContinuousTarget(state, "MOR", [0.50, 0.30, 0.14, 0.05, 0.01], 0.24);
      mixContinuousTarget(state, "TRB", [0.02, 0.06, 0.14, 0.30, 0.48], 0.24);
    }

    const contributionPragmatist =
      essential.has("economic") &&
      (essential.has("shared_values") || essential.has("civic_part")) &&
      irrelevant.has("ancestry") &&
      irrelevant.has("born_here") &&
      irrelevant.has("religion");
    if (contributionPragmatist) {
      applyContinuousSignal(state, "MAT", 0.24);
      applyContinuousSignal(state, "ZS", -0.18);
      mixContinuousTarget(state, "CU", [0.04, 0.10, 0.24, 0.36, 0.26], 0.20);
      mixContinuousTarget(state, "TRB", [0.35, 0.32, 0.22, 0.08, 0.03], 0.16);
    }
  }
}

// Q200 party-ID option key → state.partyID mapping. Stored separately from
// the Bayesian state because party loyalty is a non-ideological force used
// downstream by predictVote, not a continuous-dimension position.
const PARTY_ID_MAP: Record<string, "D" | "R" | "I" | "T" | "N"> = {
  dem: "D",
  rep: "R",
  ind: "I",
  third: "T",
  none: "N",
};

export function applySingleChoiceAnswer(
  state: RespondentState,
  q: QuestionDef,
  optionKey: string
): void {
  state.answers[q.id] = optionKey;
  registerTouches(state, q);

  // Q200 (party_identification) is a meta-question: capture partyID directly
  // on state, no Bayesian node update needed.
  if (q.id === 200 && PARTY_ID_MAP[optionKey] !== undefined) {
    state.partyID = PARTY_ID_MAP[optionKey];
  }

  // Q211 (strategic_voting) — meta-question: capture strategic-voting flag.
  if (q.id === 211) {
    state.strategicVoting = optionKey === "strategic_lesser_evil" ||
      optionKey === "depends_on_stakes";
  }

  // Q212 (negative_partisanship) — meta-question: capture never-vote parties.
  if (q.id === 212) {
    const np = new Set<string>();
    if (optionKey === "never_dem" || optionKey === "never_dem_or_rep") np.add("D");
    if (optionKey === "never_rep" || optionKey === "never_dem_or_rep") np.add("R");
    state.negativeParties = np;
  }

  const ev = q.optionEvidence?.[optionKey];
  applyOptionEvidence(state, ev);

  // Extremity → salience: if the chosen option's pos evidence concentrates
  // on pos 1 or pos 5 for a node, bump that node's salience.
  if (ev?.continuous) {
    const extremeNodes = new Set<string>();
    for (const [nodeId, upd] of Object.entries(ev.continuous)) {
      if (isExtremePosEvidence(upd?.pos)) extremeNodes.add(nodeId);
    }
    boostExtremitySalience(state, q, extremeNodes);
  }
}

export function applyMultiAnswer(
  state: RespondentState,
  q: QuestionDef,
  optionKeys: string[]
): void {
  const unique = Array.from(new Set(optionKeys.filter(Boolean)));
  state.answers[q.id] = unique;
  registerTouches(state, q);

  const extremeNodes = new Set<string>();
  for (const optionKey of unique) {
    const ev = q.optionEvidence?.[optionKey];
    applyOptionEvidence(state, ev);
    if (ev?.continuous) {
      for (const [nodeId, upd] of Object.entries(ev.continuous)) {
        if (isExtremePosEvidence(upd?.pos)) extremeNodes.add(nodeId);
      }
    }
  }
  boostExtremitySalience(state, q, extremeNodes);
}

export function applySliderAnswer(
  state: RespondentState,
  q: QuestionDef,
  rawValue: number
): void {
  state.answers[q.id] = rawValue;
  registerTouches(state, q);

  if (!q.sliderMap) return;
  const bucket = Object.keys(q.sliderMap).find((k) => {
    const parts = k.split("-").map(Number);
    const lo = parts[0] ?? 0;
    const hi = parts[1] ?? 100;
    return rawValue >= lo && rawValue <= hi;
  });
  if (!bucket) return;
  applyOptionEvidence(state, q.sliderMap[bucket]);

  // Extremity → salience: landing at either end of the slider (≤20 or ≥80)
  // is a behavioral signal that the node is active. Boost salience on every
  // position-touched node this question declares.
  if (rawValue <= 20 || rawValue >= 80) {
    const posNodes = new Set(
      q.touchProfile.filter((t) => t.role === "position").map((t) => t.node as string)
    );
    boostExtremitySalience(state, q, posNodes);
  }
}

export function applyAllocationAnswer(
  state: RespondentState,
  q: QuestionDef,
  allocation: Record<string, number>
): void {
  state.answers[q.id] = allocation;
  registerTouches(state, q);

  if (!q.allocationMap) return;
  const total = Math.max(1, Object.values(allocation).reduce((a, b) => a + b, 0));
  const shares = Object.values(allocation).map(weight => weight / total);
  const sharesByKey = shareMap(allocation, total);

  for (const [bucket, weight] of Object.entries(allocation)) {
    const share = weight / total;
    const map = q.allocationMap[bucket];
    if (!map) continue;

    if (map.continuous) {
      for (const [nodeId, signal] of Object.entries(map.continuous)) {
        const node = state.continuous[nodeId as ContinuousNodeId];
        const normFactor = NODE_NORM_FACTORS[nodeId] ?? 1;
        const current = node.posDist;
        const bump = current.map((p, i) => p * Math.exp((signal ?? 0) * normFactor * share * ((i + 1) - 3)));
        node.posDist = normalize(bump as typeof node.posDist);
      }
    }

    if (map.categorical) {
      for (const [nodeId, catDist] of Object.entries(map.categorical)) {
        const node = state.categorical[nodeId as CategoricalNodeId];
        const normFactor = NODE_NORM_FACTORS[nodeId] ?? 1;
        const mixWeight = 0.35 * share * normFactor;
        const mixed = node.catDist.map((v, i) => v * (1 - mixWeight) + (catDist[i] ?? 0) * mixWeight);
        node.catDist = normalize(mixed as typeof node.catDist);
      }
    }

    if (map.trbAnchor) {
      const scaled: Partial<Record<"national" | "ideological" | "religious" | "class" | "ethnic_racial" | "global" | "mixed_none", number>> = {};
      for (const [k, v] of Object.entries(map.trbAnchor)) {
        scaled[k as keyof typeof scaled] = v * share;
      }
      state.trbAnchor.dist = addToAnchorDist(state.trbAnchor.dist, scaled);
      state.trbAnchor.touches += 1;
    }
  }

  const salienceTouches = q.touchProfile.filter(t => t.role === "salience");
  if (!salienceTouches.length) {
    applyAllocationShapeSignals(state, q, sharesByKey);
    return;
  }

  const hhi = shares.reduce((sum, s) => sum + s * s, 0);
  const concentration = Math.max(0, Math.min(1, (hhi - 0.25) / 0.75));
  const salLikelihood: SalienceDist =
    concentration >= 0.75 ? [0.03, 0.08, 0.24, 0.65] :
    concentration >= 0.5 ? [0.06, 0.14, 0.32, 0.48] :
    concentration >= 0.25 ? [0.12, 0.22, 0.34, 0.32] :
    [0.22, 0.30, 0.28, 0.20];

  for (const touch of salienceTouches) {
    if (touch.kind === "continuous") {
      if (isSelfNode(touch.node)) continue;
      const node = state.continuous[touch.node as ContinuousNodeId];
      node.salDist = multiplyAndNormalize(node.salDist, salLikelihood);
    } else if (touch.kind === "categorical") {
      const node = state.categorical[touch.node as CategoricalNodeId];
      node.salDist = multiplyAndNormalize(node.salDist, salLikelihood);
    }
  }

  applyAllocationShapeSignals(state, q, sharesByKey);
}

export function applyRankingAnswer(
  state: RespondentState,
  q: QuestionDef,
  ranking: string[]
): void {
  state.answers[q.id] = ranking;
  registerTouches(state, q);

  if (!q.rankingMap) return;
  const weights = [1.0, 0.8, 0.55, 0.35, 0.2, 0.0];

  // Check if this question declares salience in its touchProfile
  const hasSalience = q.touchProfile.some(t => t.role === "salience");

  ranking.forEach((item, idx) => {
    const rankWeight = weights[idx] ?? 0;
    const bottomAntiWeight =
      idx === ranking.length - 1 ? -0.30 :
      idx === ranking.length - 2 && ranking.length >= 5 ? -0.15 :
      0;
    const scalarWeight = rankWeight + bottomAntiWeight;
    const map = q.rankingMap?.[item];
    if (!map) return;

    // Rank-based salience likelihood for this position
    const salLikelihood = hasSalience && idx < RANK_SAL.length ? RANK_SAL[idx] : null;

    if (map.continuous) {
      for (const [nodeId, signal] of Object.entries(map.continuous)) {
        const node = state.continuous[nodeId as ContinuousNodeId];
        const normFactor = NODE_NORM_FACTORS[nodeId] ?? 1;
        // Scalar-only path: ranking questions store deltas as numbers; the
        // {pos} object shape is for priority_sort and is handled by
        // applyPrioritySort, so skip non-numeric values here.
        const scalar = typeof signal === "number" ? signal : 0;
        const bump = node.posDist.map((p, i) => p * Math.exp(scalar * normFactor * scalarWeight * ((i + 1) - 3)));
        node.posDist = normalize(bump as typeof node.posDist);
        if (salLikelihood && !isSelfNode(nodeId)) {
          node.salDist = multiplyAndNormalize(node.salDist, salLikelihood);
        }
      }
    }

    if (map.categorical) {
      for (const [nodeId, catDist] of Object.entries(map.categorical)) {
        const node = state.categorical[nodeId as CategoricalNodeId];
        const normFactor = NODE_NORM_FACTORS[nodeId] ?? 1;
        const mixWeight = 0.4 * Math.abs(scalarWeight) * normFactor;
        const target = scalarWeight < 0 ? invertCatDist(catDist) : catDist;
        const mixed = node.catDist.map((v, i) => v * (1 - mixWeight) + (target[i] ?? 0) * mixWeight);
        node.catDist = normalize(mixed as typeof node.catDist);
        if (salLikelihood) {
          node.salDist = multiplyAndNormalize(node.salDist, salLikelihood);
        }
      }
    }

    if (map.trbAnchor) {
      const scaled: Partial<Record<"national" | "ideological" | "religious" | "class" | "ethnic_racial" | "global" | "mixed_none", number>> = {};
      for (const [k, v] of Object.entries(map.trbAnchor)) {
        scaled[k as keyof typeof scaled] = v * scalarWeight;
      }
      state.trbAnchor.dist = addToAnchorDist(state.trbAnchor.dist, scaled);
      state.trbAnchor.touches += 1;
    }
  });
}

/**
 * Apply a top-N / bottom-N best-worst answer as a per-item salience update.
 *
 * Unlike applyRankingAnswer, which weights evidence by rank position within a flat
 * ordering, this routine treats every item independently: items picked as "best"
 * receive SAL_IF_BEST; items picked as "worst" receive SAL_IF_WORST; everything
 * else receives SAL_IF_MIDDLE. The rankingMap entry for each item identifies which
 * nodes that item's salience evidence applies to; the rankingMap's scalar values
 * are intentionally ignored here (this is a salience-only question).
 */
export function applyBestWorstSalience(
  state: RespondentState,
  q: QuestionDef,
  best: string[],
  worst: string[],
  allItems: string[]
): void {
  state.answers[q.id] = { best: best.slice(), worst: worst.slice() };
  registerTouches(state, q);

  const itemMap = q.bestWorstMap ?? q.rankingMap;
  if (!itemMap) return;

  const bestSet = new Set(best);
  const worstSet = new Set(worst);

  // Per-question salience aggregation. Apply ONE salience update per node,
  // not one per item — otherwise a question whose 6 items all reference the
  // same node (Q89, EPS) would multiply 6 likelihoods into the same posterior
  // and collapse it. For Q86/Q88 each item maps to a distinct node, so this
  // collapses to the previous per-item behavior with no change.
  type Bucket = "best" | "worst" | "middle";
  const continuousBuckets = new Map<string, Set<Bucket>>();
  const categoricalBuckets = new Map<string, Set<Bucket>>();
  const bucketFor = (item: string): Bucket =>
    bestSet.has(item) ? "best" : worstSet.has(item) ? "worst" : "middle";

  for (const item of allItems) {
    const map = itemMap[item];
    if (!map) continue;
    const b = bucketFor(item);
    if (map.continuous) {
      for (const nodeId of Object.keys(map.continuous)) {
        if (!continuousBuckets.has(nodeId)) continuousBuckets.set(nodeId, new Set());
        continuousBuckets.get(nodeId)!.add(b);
      }
    }
    if (map.categorical) {
      for (const nodeId of Object.keys(map.categorical)) {
        if (!categoricalBuckets.has(nodeId)) categoricalBuckets.set(nodeId, new Set());
        categoricalBuckets.get(nodeId)!.add(b);
      }
    }
  }

  // Pick the strongest signal observed: best > worst > middle. Engaging with
  // a node at either pole signals salience; otherwise it gets the mild
  // "didn't pick this" pull toward low-salience.
  //
  // Forced-pick detection: if the same node is also referenced by a "middle"
  // item, the question is a category-pick battery (Q89 EPS) where every item
  // touches the same node — the respondent was forced to choose, so the best/
  // worst signal is weaker evidence of genuine importance. Use milder FORCED
  // variants. Otherwise it's a node-salience battery (Q86/Q88) where each item
  // maps to a distinct node — middle items reference different nodes, and the
  // best/worst signal is real relative importance.
  function resolveSal(buckets: Set<Bucket>): SalienceDist {
    const forced = buckets.has("middle");
    if (buckets.has("best")) return forced ? SAL_IF_BEST_FORCED : SAL_IF_BEST;
    if (buckets.has("worst")) return forced ? SAL_IF_WORST_FORCED : SAL_IF_WORST;
    return SAL_IF_MIDDLE;
  }

  for (const [nodeId, buckets] of continuousBuckets) {
    if (isSelfNode(nodeId)) continue;
    const node = state.continuous[nodeId as ContinuousNodeId];
    if (!node) continue;
    node.salDist = multiplyAndNormalize(node.salDist, resolveSal(buckets));
  }
  for (const [nodeId, buckets] of categoricalBuckets) {
    const node = state.categorical[nodeId as CategoricalNodeId];
    if (!node) continue;
    node.salDist = multiplyAndNormalize(node.salDist, resolveSal(buckets));
  }

  // Category mixing: separate per-item pass over best/worst items only.
  // Best pulls the categorical posterior toward the item's prototype; worst
  // pushes it toward the prototype's inverse. Middle items contribute nothing
  // to category — only to salience above.
  for (const item of allItems) {
    const map = itemMap[item];
    if (!map?.categorical) continue;
    const isBest = bestSet.has(item);
    const isWorst = worstSet.has(item);
    if (!isBest && !isWorst) continue;
    for (const [nodeId, catDist] of Object.entries(map.categorical)) {
      const node = state.categorical[nodeId as CategoricalNodeId];
      if (!node || !catDist) continue;
      const w = isBest ? BW_BEST_CAT_MIX : BW_WORST_CAT_MIX;
      const target = isBest ? catDist : invertCatDist(catDist);
      const mixed = node.catDist.map((v, i) => v * (1 - w) + target[i]! * w);
      node.catDist = normalize(mixed as typeof node.catDist);
    }
  }

  // Continuous position mixing: for pole-battery questions (Q93-Q96), each
  // item carries a `pos` distribution that encodes which pole it represents.
  // Best pulls the position posterior toward the pole; worst pushes it toward
  // the inverted distribution. Lighter mix than category (position from a
  // priority pick is informative but noisy).
  for (const item of allItems) {
    const map = itemMap[item];
    if (!map?.continuous) continue;
    const isBest = bestSet.has(item);
    const isWorst = worstSet.has(item);
    if (!isBest && !isWorst) continue;
    for (const [nodeId, evidence] of Object.entries(map.continuous)) {
      if (typeof evidence === "number") {
        applyContinuousSignal(
          state,
          nodeId as ContinuousNodeId,
          evidence,
          isBest ? BW_BEST_POS_MIX : -BW_WORST_POS_MIX
        );
        continue;
      }
      if (typeof evidence !== "object" || !evidence || !evidence.pos) continue;
      const pos = evidence.pos;
      const node = state.continuous[nodeId as ContinuousNodeId];
      if (!node) continue;
      const w = isBest ? BW_BEST_POS_MIX : BW_WORST_POS_MIX;
      const sum = pos.reduce((a: number, b: number) => a + b, 0) || 1;
      const target = isBest
        ? (pos.map((p: number) => p / sum) as typeof node.posDist)
        : (pos.map((p: number) => (1 - p / sum)) as typeof node.posDist);
      const tSum = target.reduce((a: number, b: number) => a + b, 0) || 1;
      const tNorm = target.map((p: number) => p / tSum) as typeof node.posDist;
      const mixed = node.posDist.map((v, i) => v * (1 - w) + tNorm[i]! * w);
      node.posDist = normalize(mixed as typeof node.posDist);
    }
  }
}

/**
 * Apply a priority-sort (card-sort) answer with four buckets:
 *   supportHigh — "central to my politics" (care + agree, strong)
 *   supportMid  — "I support it, but it isn't central"       (care + agree, mild)
 *   neutral     — "not central to my politics"               (don't care)
 *   opposeHigh  — "opposing this is central to my politics"  (care + disagree, strong)
 *
 * Salience (aggregated per-node across items):
 *   supportHigh OR opposeHigh present → SAL_PRIORITY_HIGH
 *   supportMid present                → SAL_PRIORITY_MID
 *   neutral only                      → SAL_PRIORITY_LOW
 *
 * Position (per-item mixing):
 *   supportHigh → pull toward pole at PRIORITY_HIGH_POS_MIX
 *   supportMid  → pull toward pole at PRIORITY_MID_POS_MIX
 *   neutral     → skip
 *   opposeHigh  → pull toward INVERTED pole distribution at PRIORITY_HIGH_POS_MIX
 *                 (same inversion pattern as applyBestWorstSalience's worst case)
 */
export function applyPrioritySort(
  state: RespondentState,
  q: QuestionDef,
  placements: {
    supportHigh?: string[];
    supportMid?: string[];
    neutral?: string[];
    opposeHigh?: string[];
  },
  allItems: string[]
): void {
  // Tolerate 3-bucket priority_sort questions (e.g. Q103 salience screener)
  // that omit the opposeHigh bucket. Default any missing bucket to [].
  const supportHigh = placements.supportHigh ?? [];
  const supportMid  = placements.supportMid  ?? [];
  const neutral     = placements.neutral     ?? [];
  const opposeHigh  = placements.opposeHigh  ?? [];
  placements = { supportHigh, supportMid, neutral, opposeHigh };
  state.answers[q.id] = {
    supportHigh: supportHigh.slice(),
    supportMid:  supportMid.slice(),
    neutral:     neutral.slice(),
    opposeHigh:  opposeHigh.slice(),
  };
  registerTouches(state, q);

  if (!q.rankingMap) return;

  const supportHighSet = new Set(placements.supportHigh);
  const supportMidSet  = new Set(placements.supportMid);
  const opposeHighSet  = new Set(placements.opposeHigh);

  type Bucket = "supportHigh" | "supportMid" | "neutral" | "opposeHigh";
  const bucketFor = (item: string): Bucket =>
    supportHighSet.has(item) ? "supportHigh"
      : opposeHighSet.has(item) ? "opposeHigh"
      : supportMidSet.has(item) ? "supportMid"
      : "neutral";

  // Per-node salience aggregation: record which buckets each node appears in,
  // then apply one salience update per node using the strongest signal.
  const continuousBuckets = new Map<string, Set<Bucket>>();
  const categoricalBuckets = new Map<string, Set<Bucket>>();
  for (const item of allItems) {
    const map = q.rankingMap[item];
    if (!map) continue;
    const b = bucketFor(item);
    if (map.continuous) {
      for (const nodeId of Object.keys(map.continuous)) {
        if (!continuousBuckets.has(nodeId)) continuousBuckets.set(nodeId, new Set());
        continuousBuckets.get(nodeId)!.add(b);
      }
    }
    if (map.categorical) {
      for (const nodeId of Object.keys(map.categorical)) {
        if (!categoricalBuckets.has(nodeId)) categoricalBuckets.set(nodeId, new Set());
        categoricalBuckets.get(nodeId)!.add(b);
      }
    }
  }

  // Per-question override (used by salience screeners like Q75 that ship harder
  // likelihoods than the Q93-tuned defaults). Absent → use module defaults.
  const salHigh = q.salienceBuckets?.supportHigh ?? SAL_PRIORITY_HIGH;
  const salMid = q.salienceBuckets?.supportMid ?? SAL_PRIORITY_MID;
  const salLow = q.salienceBuckets?.neutral ?? SAL_PRIORITY_LOW;
  const salOpposeHigh = q.salienceBuckets?.opposeHigh ?? SAL_PRIORITY_HIGH;

  function resolveSal(buckets: Set<Bucket>): SalienceDist {
    if (buckets.has("supportHigh")) return salHigh;
    if (buckets.has("opposeHigh")) return salOpposeHigh;
    if (buckets.has("supportMid")) return salMid;
    return salLow;
  }

  for (const [nodeId, buckets] of continuousBuckets) {
    if (isSelfNode(nodeId)) continue;
    const node = state.continuous[nodeId as ContinuousNodeId];
    if (!node) continue;
    node.salDist = multiplyAndNormalize(node.salDist, resolveSal(buckets));
  }
  for (const [nodeId, buckets] of categoricalBuckets) {
    const node = state.categorical[nodeId as CategoricalNodeId];
    if (!node) continue;
    node.salDist = multiplyAndNormalize(node.salDist, resolveSal(buckets));
  }

  // Per-item continuous position mixing. Support buckets pull toward the pole;
  // oppose pulls toward the inverted pole (anti-pole); neutral skips.
  for (const item of allItems) {
    const map = q.rankingMap[item];
    if (!map?.continuous) continue;
    const bucket = bucketFor(item);
    if (bucket === "neutral") continue;
    const w = (bucket === "supportMid") ? PRIORITY_MID_POS_MIX : PRIORITY_HIGH_POS_MIX;
    const invert = (bucket === "opposeHigh");
    for (const [nodeId, evidence] of Object.entries(map.continuous)) {
      // priority_sort uses {pos} objects; scalars are for ranking and skip here
      if (typeof evidence !== "object" || !evidence || !evidence.pos) continue;
      const pos = evidence.pos;
      const node = state.continuous[nodeId as ContinuousNodeId];
      if (!node) continue;
      const sum = pos.reduce((a: number, b: number) => a + b, 0) || 1;
      const raw = invert
        ? pos.map((p: number) => 1 - p / sum)
        : pos.map((p: number) => p / sum);
      const rawSum = raw.reduce((a: number, b: number) => a + b, 0) || 1;
      const target = raw.map((p: number) => p / rawSum) as typeof node.posDist;
      const mixed = node.posDist.map((v, i) => v * (1 - w) + target[i]! * w);
      node.posDist = normalize(mixed as typeof node.posDist);
    }
  }

  // Per-item trbAnchor signals. Each rankingMap entry with a trbAnchor payload
  // contributes exp(signal * bucketScale) toward that anchor. If the respondent
  // places every item in "neutral", no anchor gets boosted and the posterior
  // stays uniform — reading as low TRB salience / no dominant anchor.
  let anchorTouched = false;
  for (const item of allItems) {
    const map = q.rankingMap[item];
    if (!map?.trbAnchor) continue;
    const bucket = bucketFor(item);
    if (bucket === "neutral") continue;
    const scale = (bucket === "supportHigh") ? 1.0
                : (bucket === "supportMid") ? 0.4
                : (bucket === "opposeHigh") ? -1.0 // "not me" — pushes anchor away
                : 0;
    if (scale === 0) continue;
    const scaled: Partial<Record<keyof typeof map.trbAnchor, number>> = {};
    for (const [k, v] of Object.entries(map.trbAnchor)) {
      scaled[k as keyof typeof scaled] = (v ?? 0) * scale;
    }
    state.trbAnchor.dist = addToAnchorDist(state.trbAnchor.dist, scaled);
    anchorTouched = true;
  }
  if (anchorTouched) state.trbAnchor.touches += 1;

  applyPriorityPatternSignals(state, q, { supportHigh, supportMid, neutral, opposeHigh });
}

/**
 * Dual-axis answer. A single grid tap produces (x, y) both in [0, 1]:
 *   x → position target via linear interp between `xLow` and `xHigh`,
 *       convex-mixed into posDist at DUAL_AXIS_POS_MIX.
 *   y → salience likelihood via `dualAxisYtoSal`, multiplied into salDist.
 *
 * Applies to the single node declared in q.dualAxisMap.node. Any additional
 * touchProfile entries are registered but not updated here — the gesture
 * directly signals only that node.
 */
export function applyDualAxisAnswer(
  state: RespondentState,
  q: QuestionDef,
  answer: { x: number; y: number }
): void {
  const x = Math.max(0, Math.min(1, answer.x));
  const y = Math.max(0, Math.min(1, answer.y));
  state.answers[q.id] = { x, y };
  registerTouches(state, q);

  if (!q.dualAxisMap) return;
  const map = q.dualAxisMap;
  const node = state.continuous[map.node as ContinuousNodeId];
  if (!node) return;

  // Position: Gaussian target peaked at index 4*x (so x=0→pos1, x=0.5→pos3,
  // x=1→pos5), sigma=1.0 in index units. Replaces the earlier linear interp
  // between xLow and xHigh, which produced a bathtub at moderate x (x=0.5
  // returned a flat/valley distribution at pos=3, pulling moderate archetypes
  // off-position). xLow/xHigh are retained on the type for UI labeling only.
  const targetIdx = 4 * x;
  const sigma = 0.8;
  const raw = [0, 1, 2, 3, 4].map(i => {
    const d = i - targetIdx;
    return Math.exp(-0.5 * (d * d) / (sigma * sigma));
  });
  const rawSum = raw.reduce((a, b) => a + b, 0) || 1;
  const normTarget = raw.map(v => v / rawSum);
  const mixed = node.posDist.map((v, i) => v * (1 - DUAL_AXIS_POS_MIX) + (normTarget[i] ?? 0) * DUAL_AXIS_POS_MIX);
  node.posDist = normalize(mixed as typeof node.posDist);

  // Salience: y bucket → likelihood ratio, multiply into salDist.
  // SELF-cluster nodes skip sal write (activation-only).
  if (!isSelfNode(map.node)) {
    node.salDist = multiplyAndNormalize(node.salDist, dualAxisYtoSal(y));
  }
}

export function applyPairwiseAnswer(
  state: RespondentState,
  q: QuestionDef,
  answers: Record<string, string>
): void {
  state.answers[q.id] = answers;
  registerTouches(state, q);

  if (!q.pairMaps) return;
  for (const [pairId, chosen] of Object.entries(answers)) {
    const map: PairOptionMap | undefined = q.pairMaps[pairId]?.[chosen];
    if (!map) continue;

    if (map.continuous) {
      for (const [nodeId, signal] of Object.entries(map.continuous)) {
        const node = state.continuous[nodeId as ContinuousNodeId];
        const normFactor = NODE_NORM_FACTORS[nodeId] ?? 1;
        const bump = node.posDist.map((p, i) => p * Math.exp((signal ?? 0) * normFactor * ((i + 1) - 3)));
        node.posDist = normalize(bump as typeof node.posDist);
      }
    }

    if (map.categorical) {
      for (const [nodeId, catDist] of Object.entries(map.categorical)) {
        const node = state.categorical[nodeId as CategoricalNodeId];
        const normFactor = NODE_NORM_FACTORS[nodeId] ?? 1;
        const mixWeight = 0.4 * normFactor;
        const mixed = node.catDist.map((v, i) => v * (1 - mixWeight) + (catDist[i] ?? 0) * mixWeight);
        node.catDist = normalize(mixed as typeof node.catDist);
      }
    }
  }
}
