import type { NodeDef } from "../types.js";

// ── CANONICAL POLARITY LEGEND (verified against archetype atlas 2026-03-28) ──
//
// ENDS:
//   MAT: 1 = redistribution / egalitarian,          5 = free market / laissez-faire
//        Note (2026-04-26): MAT is *direction* of economic policy (egalitarian vs
//        market), NOT *scope* of state. "I want a big state" lives on ONT_S
//        (belief in institutional capacity), not MAT. A redistributionist who wants
//        a smaller state to do it (e.g., UBI-libertarian) is low MAT + low ONT_S; a
//        market-conservative who wants robust institutions to enforce contracts and
//        property rights is high MAT + high ONT_S. Questions that bundle "big state"
//        with "redistribution" should be split or down-weighted.
//   CD:  Social Direction — covers gender, sexuality, reproductive rights, LGBTQ
//        rights, transgender issues, marriage, religious accommodation, and how
//        fast (or whether) social conventions should evolve. The "cultural" label
//        understates the stakes: most issues on this axis (abortion access,
//        marriage rights, gender-affirming care, religious-exemption laws) have
//        direct legal and material consequences for people's lives. Treat CD as
//        social-direction-with-legal-and-material-ramifications, not just
//        culture-as-style.
//          1 = progressive / open / liberalizing direction
//          5 = traditional / conservative / restorationist direction
//        Note (2026-04-26): canonical scope clarified to acknowledge that CD
//        questions probe rights and policy stakes, not just cultural aesthetics.
//   CU:  Uniformity — covers ALL forms of within-polity uniformity, not only
//        culture-as-style. The axis spans uniformity vs pluralism along language,
//        race, religion, worldview, "what makes a good life," civic norms, and
//        political thought. Two poles:
//          1 = uniformity / "everyone here should be the same" — same religion,
//              same race / ethnicity, same language, same worldview, same
//              conception of a good life, shared civic-religious traditions.
//              Nativist, integrationist, ethno-religious-particularist all anchor
//              here.
//          5 = pluralism / "no issue with any form of plurality" — different
//              worldviews, lifestyles, religions, languages, conceptions of the
//              good life, and ways of organizing community can coexist as equals;
//              the polity does not need a shared standard.
//        Note (2026-04-26): canonical scope broadened from "cultural pluralism"
//        to full within-polity pluralism (including worldview, religious, and
//        good-life pluralism). Existing question evidence (Q102 membership
//        criteria, Q67 universal-vs-local) already captures the broader concept;
//        only user-facing labels and prompts needed to expand. CU is orthogonal
//        to MOR scope: a respondent can want maximum within-polity uniformity
//        (low CU) AND a wide moral circle outside the polity (high MOR).
//   MOR: 1 = narrow moral circle / particularist,    5 = wide moral circle / universalist
//
// MEANS:
//   PRO: 1 = outcome-focused / anti-procedural,      5 = rules-bound / procedural
//   COM: 1 = uncompromising / principled,             5 = compromising / consensus-seeking
//   EPS: Epistemic Style — categorical (6 distinct cognitive postures, not a 1-5 axis).
//        The conceptual target is *what kind of evidence or authority you trust to
//        determine what is politically true* — i.e., what makes a claim count as
//        true enough to act on.
//          empiricist     — evidence-first; studies, data, measurement, observable
//                           outcomes. "Show me the numbers."
//          institutionalist — expert / credentialed processes; courts, agencies,
//                           peer review, professional standards. "What does the
//                           expert consensus say?"
//          traditionalist — inherited wisdom; religious teaching, long-standing
//                           customs, the test of time. "What have generations
//                           shown us works?"
//          intuitionist   — moral intuition / conscience; gut sense of right and
//                           wrong. "I just know this is wrong."
//          autonomous     — independent reasoning from first principles; no
//                           authority gets automatic deference. "Let me work it
//                           out myself."
//          nihilist       — radical skepticism; most sources are compromised,
//                           default suspicion. "They're all lying."
//        Note (2026-04-26): EPS-institutionalist is conceptually distinct from
//        high ONT_S. EPS-institutionalist = "I trust expert consensus to KNOW
//        what's true." High ONT_S = "I believe institutions can ACT EFFECTIVELY
//        and produce good outcomes." These come apart: a right-of-center policy
//        intellectual can be EPS-institutionalist + low ONT_S (trusts expert
//        diagnoses but not state remedies); a populist activist can be
//        EPS-empiricist + low ONT_S (trusts data but not institutional capacity
//        to act on it). Question evidence should not conflate the two.
//   AES: Aesthetic Style — categorical (6 distinct political aesthetics, not a 1-5
//        axis). The conceptual target is *what political-leadership style appeals
//        to you stylistically* — presentation, persona, rhetorical mode, tone,
//        bearing — INDEPENDENT of belief content. A traditionalist can be
//        visionary, a progressive can be statesman, a libertarian can be
//        plainspoken. Belief content lives on MAT/CD/CU/MOR/PRO/ONT_S; AES is
//        only about HOW the leader presents and talks, not WHAT they believe.
//          statesman   — formal and dignified, measured tone, ceremonial
//                        register, presidential bearing. Cool, restrained.
//                        (Stylistic examples regardless of ideology:
//                        Eisenhower, Obama in 2008 mode, Liz Cheney delivery,
//                        Romney late-phase, Margaret Thatcher in formal mode.)
//          technocrat  — precise and analytical, expert-coded delivery,
//                        comfortable with technical detail and jargon. Slide-
//                        deck register. (Stylistic examples: Buttigieg,
//                        Macron, Bloomberg, Elizabeth Warren in policy mode.)
//          pastoral    — warm hometown register, regional cadence, family-
//                        and-community language, evocative and emotional.
//                        Speaks like a small-town/community member.
//                        (Stylistic examples regardless of ideology:
//                        rural Republicans on stump, southern Democrats,
//                        Bill Clinton "I feel your pain", Jimmy Carter
//                        peanut-farmer register.)
//          plainspoken — direct and casual, unscripted, refuses polish and
//                        political theater, talks like a regular person.
//                        The "I'm one of you" register against elite polish.
//                        (Renamed from "authentic" 2026-04-26 because
//                        authenticity is a quality every aesthetic can have,
//                        not a distinct category. Examples: Bernie unfiltered,
//                        "Scranton Joe", Truman, Reagan-as-cowboy, Vance-as-
//                        hillbilly, Trump unscripted.)
//          fighter     — combative tone, willing to attack opponents
//                        directly, confrontational delivery, doesn't soften.
//                        (Examples regardless of ideology: AOC stump mode,
//                        Trump rally mode, Christie prosecutor mode, RFK Jr.
//                        Sr. mode, Newt Gingrich.)
//          visionary   — lyrical and aspirational, evocative-imagistic
//                        rhetoric, paints pictures with words. Often soaring.
//                        (Examples regardless of ideology: Obama "Yes We
//                        Can", JFK moonshot, Bernie "political revolution",
//                        Reagan "city on a hill", AOC Green New Deal.)
//        Note (2026-04-26): AES_CATEGORIES position 3 renamed authentic →
//        plainspoken. CategoricalDist arrays are positional, so the rename
//        does not change any archetype prototype values; only the key changed.
//        Note (2026-04-26): canonical descriptions rewritten to be pure-style.
//        Previous text contained belief contamination (statesman "constitutional"
//        / "institution-minded" = ONT_S/PRO content; pastoral "tradition-aware"
//        / "protective of place" = CD/CU content; technocrat "data-driven" =
//        EPS content). AES descriptions now describe ONLY presentation mode.
//
// REALITY:
//   ZS:    Zero-Sum vs Positive-Sum — structural worldview about whether systems
//          (economic, political, cultural, civilizational) produce gains by
//          cooperation that benefit everyone, or by competition where one side
//          gains at another's expense.
//            1 = positive-sum / cooperative — growth mindset; trade is win-win,
//                cultural exchange enriches everyone, political disagreements can
//                produce mutual gains, status is not fixed
//            5 = zero-sum / competitive — fixed-pie thinking; my gain requires
//                someone else's loss, in economics (resources are finite), politics
//                (one side's win is another's loss), and culture (cultural change
//                = displacement of one group by another)
//          Note (2026-04-26): ZS scope is broad — covers economic, political, AND
//          cultural domains. A respondent who is mixed across these (e.g.,
//          positive-sum economically but zero-sum politically) lands legitimately
//          in the middle. Distinguished from ONT_H: ZS is about the structure of
//          the world (cooperative vs competitive); ONT_H is about whether HUMANS
//          can be reshaped by cultivation. They tend to correlate empirically
//          (zero-sum thinkers often see humans as fixed too) but come apart in
//          principled cases — Adam Smith was a malleability skeptic but a
//          positive-sum theorist (low ONT_H, low ZS); a left-populist can be a
//          malleability optimist who sees the elite as extracting from workers
//          (high ONT_H, high ZS).
//   ONT_H: 1 = humans are fixed; cultivation cannot reshape character or capability,
//          5 = humans are malleable; education, institutions, modeling, and tradition
//              can substantially reshape character and capability.
//          Note (2026-04-26): reframed from the older "optimistic vs pessimistic about
//          human nature" framing because that conflated metaphysical claims about fixed
//          human nature with the politically load-bearing question — *can humans be
//          changed by cultivation?* The fixed-goodness axis collapses two distinct
//          political postures: a Hobbesian who thinks people are bad-but-malleable
//          (high ONT_H, supports discipline/education) and a Romantic primitivist who
//          thinks people are good-but-fixed (low ONT_H, anti-institutional) end up on
//          the same side under the older framing despite producing opposite politics.
//          The malleability framing also makes the cleavage with ONT_S sharper: ONT_H
//          is about whether *humans* can be reshaped; ONT_S is about whether
//          *institutions can act effectively to do the reshaping or solve problems*.
//          A Burkean (humans malleable via family/tradition, NOT via state) is high
//          ONT_H + low/mid ONT_S; a Progressive (humans malleable via state programs)
//          is high ONT_H + high ONT_S; a libertarian fatalist (humans fixed, state
//          can't help) is low ONT_H + low ONT_S.
//   ONT_S: 1 = institutional nihilism / institutions are not the right tool /
//              shrink them / they get captured or sclerotic and won't fix things.
//              Libertarianism, small-government conservatism, accelerationism, and
//              "the system is rigged forever" populism all anchor here.
//          5 = institutional capacity belief — well-designed institutions and state
//              structures CAN solve collective problems and produce good outcomes.
//              Strong lawful national and global institutions are essential to
//              human flourishing.
//          Note (2026-04-26): reframed twice now. First reframe (2026-04-25) moved
//              from "system broken vs system working" (which conflated current
//              performance with normative institutional belief) to "anti-institutional
//              vs institutionally constructive". Second reframe (2026-04-26) tightens
//              the low pole: a revolutionary who wants to tear down current
//              institutions to *build better ones* is NOT low ONT_S — they believe
//              institutions can work. Low ONT_S means the tool itself is wrong:
//              institutions in principle won't or can't do the job. Q214/Q215/Q216
//              are designed against this clarified framing; older causal-attribution
//              probes (Q15 inequality, Q20 bad-outcomes, Q83 broken-politics) measure
//              structural attribution rather than institutional capacity belief and
//              have been decoupled from ONT_S.
//
// SELF:
//   PF:  1 = independent / non-partisan,              5 = strong partisan identity
//   TRB: 1 = universalist / low tribal,               5 = tribal / in-group focused
//   ENG: 1 = apolitical / disengaged,                 5 = highly politically engaged

export const NODE_DEFS: NodeDef[] = [
  { id: "MAT", type: "continuous", cluster: "ENDS" },
  { id: "CD", type: "continuous", cluster: "ENDS" },
  { id: "CU", type: "continuous", cluster: "ENDS" },
  { id: "MOR", type: "continuous", cluster: "ENDS" },

  { id: "PRO", type: "continuous", cluster: "MEANS" },
  { id: "EPS", type: "categorical", cluster: "MEANS" },
  { id: "AES", type: "categorical", cluster: "MEANS" },
  { id: "COM", type: "continuous", cluster: "MEANS" },

  { id: "ZS", type: "continuous", cluster: "REALITY" },
  { id: "ONT_H", type: "continuous", cluster: "REALITY" },
  { id: "ONT_S", type: "continuous", cluster: "REALITY" },

  { id: "PF", type: "continuous", cluster: "SELF" },
  { id: "TRB", type: "continuous", cluster: "SELF" },
  { id: "ENG", type: "continuous", cluster: "SELF" }
];

export const CONTINUOUS_NODES = NODE_DEFS.filter(
  (n) => n.type === "continuous"
).map((n) => n.id) as Array<
  | "MAT"
  | "CD"
  | "CU"
  | "MOR"
  | "PRO"
  | "COM"
  | "ZS"
  | "ONT_H"
  | "ONT_S"
  | "PF"
  | "TRB"
  | "ENG"
>;

export const CATEGORICAL_NODES = NODE_DEFS.filter(
  (n) => n.type === "categorical"
).map((n) => n.id) as Array<"EPS" | "AES">;

/**
 * SELF-cluster nodes are *activation-only*: they describe the respondent's
 * relationship to politics, not a position about politics. For PF/TRB/ENG,
 * the `pos` (1-5) scale doubles as the salience scale — there is no meaningful
 * state of e.g. "strong partisan identity that doesn't matter to you", or
 * "politically disengaged but politics matters a lot". See ADR-005.
 *
 * The engine skips `salDist` reads/writes for these nodes; archetype defs
 * omit `sal` fields; questions carry only `role: "position"` touches for them.
 */
export const SELF_NODES = ["PF", "TRB", "ENG"] as const;
export type SelfNodeId = (typeof SELF_NODES)[number];
export function isSelfNode(id: string): id is SelfNodeId {
  return (SELF_NODES as readonly string[]).includes(id);
}
