import type { RespondentState, TrbAnchor, ContinuousNodeId, CategoricalNodeId } from "../types.js";
import type { EngagementLabel } from "../engine/engagementLabel.js";
import { isSelfNode } from "../config/nodes.js";

export type IdentityPrimaryLabel =
  | "Black Voter"
  | "White Grievance Voter"
  | "Evangelical Voter"
  | "LGBTQ Voter"
  | "Feminist Voter"
  | "Male Grievance Voter";

export type IdentityPrimaryState = "none" | "unresolved" | "latent" | "active" | "dominant";
export type IdentityPrimaryConfidence = "low" | "medium" | "high";

export interface IdentityPrimaryResult {
  state: IdentityPrimaryState;
  label?: IdentityPrimaryLabel;
  confidence?: IdentityPrimaryConfidence;
  anchor?: TrbAnchor;
  reasonCodes: string[];
  gate: {
    trb: number;
    pf: number;
    engagementLevel: EngagementLabel["level"];
    passedLatent: boolean;
    passedActive: boolean;
    passedDominant: boolean;
    policySalienceScore: number;
    highSaliencePolicyCount: number;
    passedIdeologyThinness: boolean;
    anchorMass: number;
    anchorMargin: number;
    passedAnchorDominance: boolean;
  };
}

// Ideology-thinness gate (added 2026-04-24).
//
// Identity-primary archetypes describe identity-first, ideology-thin voters.
// A user with sharp policy posteriors — strong views on multiple non-SELF
// nodes — is by definition NOT identity-primary, even if their TRB/PF/anchor
// signals would otherwise qualify. This gate enforces that.
//
// Inputs:
//   - mean expected salience across the 11 non-SELF nodes (MAT, CD, CU, MOR,
//     PRO, COM, ZS, ONT_H, ONT_S, EPS, AES)
//   - count of non-SELF nodes with E[sal] >= 2.25 ("strongly cares")
//
// Pass conditions:
//   - mean E[sal] across non-SELF nodes <= 1.25
//   - AND count of high-salience nodes <= 2
const POLICY_SALIENCE_MEAN_MAX = 1.25;
const POLICY_SALIENCE_HIGH_THRESHOLD = 2.25;
const POLICY_SALIENCE_HIGH_COUNT_MAX = 2;

// Anchor dominance gate.
const ANCHOR_MASS_MIN = 0.25;
const ANCHOR_MARGIN_MIN = 0.05;

export interface IdentityPrimaryDemographics {
  demo_ethnicity?: string;
  demo_religion?: string;
  demo_gender?: string;
  demo_lgbtq?: string;
  [key: string]: unknown;
}

const TRB_ANCHOR_ORDER: TrbAnchor[] = [
  "national",
  "ideological",
  "religious",
  "class",
  "ethnic_racial",
  "gender",
  "sexual",
  "global",
  "mixed_none",
];

function expectedContinuous(state: RespondentState, nodeId: "TRB" | "PF" | "ZS" | "CD" | "ONT_S" | "MOR"): number {
  const node = state.continuous[nodeId];
  if (!node) return 3;
  return node.posDist.reduce((sum, p, i) => sum + p * (i + 1), 0);
}

interface AnchorTopResult {
  anchor: TrbAnchor;
  mass: number;
  margin: number;
}

function topAnchorWithMargin(state: RespondentState): AnchorTopResult {
  const dist = state.trbAnchor?.dist;
  if (!dist || dist.length !== TRB_ANCHOR_ORDER.length) {
    return { anchor: "mixed_none", mass: 0, margin: 0 };
  }
  let bestIdx = 0;
  let secondMass = 0;
  for (let i = 1; i < dist.length; i++) {
    if (dist[i]! > dist[bestIdx]!) bestIdx = i;
  }
  for (let i = 0; i < dist.length; i++) {
    if (i === bestIdx) continue;
    if (dist[i]! > secondMass) secondMass = dist[i]!;
  }
  return {
    anchor: TRB_ANCHOR_ORDER[bestIdx]!,
    mass: dist[bestIdx]!,
    margin: dist[bestIdx]! - secondMass,
  };
}

function expectedSalienceContinuous(state: RespondentState, nodeId: ContinuousNodeId): number {
  const node = state.continuous[nodeId];
  if (!node) return 0;
  return node.salDist.reduce((sum, p, i) => sum + p * i, 0);
}

function expectedSalienceCategorical(state: RespondentState, nodeId: CategoricalNodeId): number {
  const node = state.categorical[nodeId];
  if (!node) return 0;
  return node.salDist.reduce((sum, p, i) => sum + p * i, 0);
}

// Compute the ideology-thinness signal across non-SELF nodes.
function computePolicySalience(state: RespondentState): { score: number; highCount: number } {
  const continuousNonSelf: ContinuousNodeId[] = [
    "MAT", "CD", "CU", "MOR", "PRO", "COM", "ZS", "ONT_H", "ONT_S",
  ];
  const categorical: CategoricalNodeId[] = ["EPS", "AES"];

  const sals: number[] = [];
  for (const nid of continuousNonSelf) {
    if (isSelfNode(nid)) continue;
    sals.push(expectedSalienceContinuous(state, nid));
  }
  for (const nid of categorical) {
    sals.push(expectedSalienceCategorical(state, nid));
  }

  const score = sals.reduce((a, b) => a + b, 0) / Math.max(1, sals.length);
  const highCount = sals.filter((s) => s >= POLICY_SALIENCE_HIGH_THRESHOLD).length;
  return { score, highCount };
}

export function resolveIdentityPrimary(
  state: RespondentState,
  engagementLabel: EngagementLabel,
  demographics?: IdentityPrimaryDemographics | null,
): IdentityPrimaryResult {
  const trb = expectedContinuous(state, "TRB");
  const pf = expectedContinuous(state, "PF");
  const { anchor, mass: anchorMass, margin: anchorMargin } = topAnchorWithMargin(state);

  // ENG leaves archetype signatures under ADR-002; engagement gating runs on
  // the standalone EngagementLabel the caller computed from state.
  const engagementActive =
    engagementLabel.level === "engaged" ||
    engagementLabel.level === "highly-engaged";
  const engagementDominant = engagementLabel.level === "highly-engaged";

  const passedLatent = trb >= 3 && pf >= 3;
  const passedActive = trb >= 4 && pf >= 4 && engagementActive;
  const passedDominant = trb >= 4 && pf >= 4 && engagementDominant;

  // Ideology-thinness gate. Identity-primary describes voters whose politics
  // is identity-first and ideology-thin. If the user has strong policy views
  // on multiple non-SELF nodes, they have ideology — return base archetype
  // even if anchor/demographic/tribal/fusion all check out.
  const { score: policySalienceScore, highCount: highSaliencePolicyCount } =
    computePolicySalience(state);
  const passedIdeologyThinness =
    policySalienceScore <= POLICY_SALIENCE_MEAN_MAX &&
    highSaliencePolicyCount <= POLICY_SALIENCE_HIGH_COUNT_MAX;

  const passedAnchorDominance =
    anchorMass >= ANCHOR_MASS_MIN && anchorMargin >= ANCHOR_MARGIN_MIN;

  const gate = {
    trb,
    pf,
    engagementLevel: engagementLabel.level,
    passedLatent,
    passedActive,
    passedDominant,
    policySalienceScore,
    highSaliencePolicyCount,
    passedIdeologyThinness,
    anchorMass,
    anchorMargin,
    passedAnchorDominance,
  };

  if (!passedLatent) {
    return { state: "none", anchor, reasonCodes: ["gate_not_met_trb_pf"], gate };
  }

  if (!passedIdeologyThinness) {
    return {
      state: "unresolved",
      confidence: "low",
      anchor,
      reasonCodes: ["policy_salience_too_high"],
      gate,
    };
  }

  if (!passedAnchorDominance) {
    return {
      state: "unresolved",
      confidence: "low",
      anchor,
      reasonCodes: ["anchor_not_dominant"],
      gate,
    };
  }

  const stateLabel: IdentityPrimaryState = passedDominant
    ? "dominant"
    : passedActive
      ? "active"
      : "latent";

  // Anchor → label routing. Each branch requires a demographic confirmation
  // matching the anchor; missing/mismatching demographics return unresolved.
  // Per 2026-04-24: White Grievance and Male Grievance are NOT separate
  // ideological postures — they're the majority-position form of identity
  // voting. So no additional grievanceSignals policy check; same gate as
  // Black/Evangelical/LGBTQ/Feminist.
  if (anchor === "ethnic_racial") {
    const race = typeof demographics?.demo_ethnicity === "string" ? demographics.demo_ethnicity : "";
    if (race === "black") {
      return {
        state: stateLabel,
        label: "Black Voter",
        confidence: passedActive ? "high" : "medium",
        anchor,
        reasonCodes: ["racial_anchor", "black_demographic_match", "ideology_thin"],
        gate,
      };
    }
    if (race === "white") {
      return {
        state: stateLabel,
        label: "White Grievance Voter",
        confidence: passedActive ? "high" : "medium",
        anchor,
        reasonCodes: ["racial_anchor", "white_demographic_match", "ideology_thin"],
        gate,
      };
    }
    return {
      state: "unresolved",
      confidence: "low",
      anchor,
      reasonCodes: ["racial_anchor", "missing_demographic_confirmation"],
      gate,
    };
  }

  if (anchor === "religious") {
    const religion = typeof demographics?.demo_religion === "string" ? demographics.demo_religion : "";
    if (religion === "christian" || religion === "evangelical") {
      return {
        state: stateLabel,
        label: "Evangelical Voter",
        confidence: passedActive ? "medium" : "low",
        anchor,
        reasonCodes: ["religious_anchor", "christian_demographic_match", "ideology_thin"],
        gate,
      };
    }
    return {
      state: "unresolved",
      confidence: "low",
      anchor,
      reasonCodes: ["religious_anchor", "missing_demographic_confirmation"],
      gate,
    };
  }

  if (anchor === "sexual") {
    const lgbtq = typeof demographics?.demo_lgbtq === "string" ? demographics.demo_lgbtq : "";
    if (lgbtq === "yes") {
      return {
        state: stateLabel,
        label: "LGBTQ Voter",
        confidence: passedActive ? "high" : "medium",
        anchor,
        reasonCodes: ["sexual_anchor", "lgbtq_demographic_match", "ideology_thin"],
        gate,
      };
    }
    return {
      state: "unresolved",
      confidence: "low",
      anchor,
      reasonCodes: ["sexual_anchor", "missing_demographic_confirmation"],
      gate,
    };
  }

  if (anchor === "gender") {
    const gender = typeof demographics?.demo_gender === "string" ? demographics.demo_gender : "";
    if (gender === "female") {
      return {
        state: stateLabel,
        label: "Feminist Voter",
        confidence: passedActive ? "high" : "medium",
        anchor,
        reasonCodes: ["gender_anchor", "female_demographic_match", "ideology_thin"],
        gate,
      };
    }
    if (gender === "male") {
      return {
        state: stateLabel,
        label: "Male Grievance Voter",
        confidence: passedActive ? "high" : "medium",
        anchor,
        reasonCodes: ["gender_anchor", "male_demographic_match", "ideology_thin"],
        gate,
      };
    }
    return {
      state: "unresolved",
      confidence: "low",
      anchor,
      reasonCodes: ["gender_anchor", "missing_demographic_confirmation"],
      gate,
    };
  }

  // Anchor is national / ideological / class / global / mixed_none — none
  // of these correspond to identity-primary categories by design. The user
  // has tribal/fusion + ideology-thin + dominant anchor, but the anchor
  // type isn't a demographic-identity category. Return unresolved with a
  // specific reason code.
  return {
    state: "unresolved",
    confidence: "low",
    anchor,
    reasonCodes: [
      anchor === "national"
        ? "national_anchor_civic_not_demographic"
        : anchor === "ideological"
          ? "ideological_anchor_no_identity_primary_match"
          : anchor === "mixed_none"
            ? "mixed_none_anchor_diffuse_identity"
            : `anchor_${anchor}_no_identity_primary_match`,
    ],
    gate,
  };
}
